[AUTH role=ORG_USER]
[GQL-OP create_bogus]
  mutation {
    createOrderFromCart(command: { cartId: "00000000-0000-0000-0000-000000000001" }) { id number status }
  }
[GQL-EXEC create_bogus]

[GQL-OP create_noauth]
  mutation { createOrderFromCart(command: { cartId: "00000000-0000-0000-0000-000000000002" }) { id } }
[GQL-EXEC create_noauth]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cart_full]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD") {
      id name status storeId customerId customerName organizationId
      itemsCount itemsQuantity type
      total { amount currency { code } }
      subTotal { amount }
      subTotalWithTax { amount }
      taxTotal { amount }
      shippingTotal { amount }
      discountTotal { amount }
      fee { amount }
      feeWithTax { amount }
      feeTotal { amount }
      feeTotalWithTax { amount }
      handlingTotal { amount }
      handlingTotalWithTax { amount }
      items { id productId sku name quantity }
      addresses { id city countryCode firstName lastName }
      coupons { code isAppliedSuccessfully }
      shipments { id shipmentMethodCode }
      payments { id paymentGatewayCode }
      availableShippingMethods { code name }
      availablePaymentMethods { code paymentMethodType }
      validationErrors { errorCode errorMessage }
    }
  }
[GQL-EXEC cart_full]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP setup_prod]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 1 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) price.USD:(0 TO) inStock_variations:true") { items { id } } }
[GQL-EXEC setup_prod]
[GQL-CAPTURE setup_prod.data.products.items.0.id → PRODUCT_ID]
[GQL-OP pre_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC pre_clear]
[GQL-OP add_item]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "{{PRODUCT_ID}}" quantity: 1 }) { id } }
[GQL-EXEC add_item]
[GQL-OP cart_items_full]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD") {
      items {
        id productId sku name quantity
        listPrice { amount }
        salePrice { amount }
        placedPrice { amount }
        extendedPrice { amount }
        discountAmount { amount }
        taxTotal { amount }
        taxPercentRate
        imageUrl
        productType
        isGift
        selectedForCheckout
        catalogId
        categoryId
      }
    }
  }
[GQL-EXEC cart_items_full]
[GQL-OP cleanup_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_clear]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP add_plain]
  mutation {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(CFG_HOODIE.id)" quantity: 1 }) {
      id itemsCount items { id productId configurationItems { id sectionId } }
    }
  }
[GQL-EXEC add_plain]
[GQL-CAPTURE add_plain.data.addItem.items.0.id → PLAIN_LINE_ITEM_ID]
[GQL-OP change_on_plain]
[GQL-VARS change_on_plain] {"configurationSections": [{"sectionId": "00000000-0000-0000-0000-000000000000", "type": "Product", "option": {"productId": "@td(CFG_HOODIE.id)", "quantity": 1}}]}
  mutation ChangeCartConfiguredItem($configurationSections: [ConfigurationSectionInput]) {
    changeCartConfiguredItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemId: "{{PLAIN_LINE_ITEM_ID}}" quantity: 1 configurationSections: $configurationSections }) {
      id validationErrors { errorCode errorMessage } items { id configurationItems { id sectionId } }
    }
  }
[GQL-EXEC change_on_plain]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id itemsCount } }
[GQL-EXEC cleanup_pre]
[GQL-OP add_1]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(BUYABLE_NO_MIN_QTY.id)" quantity: 1 }) { id itemsCount validationErrors { errorCode errorMessage } } }
[GQL-EXEC add_1]
[GQL-OP add_2]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(BUYABLE_NO_MIN_QTY.id)" quantity: 1 }) { id itemsCount validationErrors { errorCode errorMessage } } }
[GQL-EXEC add_2]
[GQL-OP add_3]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(BUYABLE_NO_MIN_QTY.id)" quantity: 1 }) { id itemsCount validationErrors { errorCode errorMessage } } }
[GQL-EXEC add_3]
[GQL-OP add_4]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(BUYABLE_NO_MIN_QTY.id)" quantity: 1 }) { id itemsCount validationErrors { errorCode errorMessage } } }
[GQL-EXEC add_4]
[GQL-OP add_5]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(BUYABLE_NO_MIN_QTY.id)" quantity: 1 }) { id itemsCount validationErrors { errorCode errorMessage } } }
[GQL-EXEC add_5]
[GQL-OP read_back]
  query { cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") { id itemsCount itemsQuantity items { id productId sku quantity } } }
[GQL-EXEC read_back]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]
